INSERT INTO apartments (title, description, location, price, price_unit, image, tag, category_group, category_type, status, rating, review_count)
VALUES
    ('城市之心精致公寓', '位于市中心，步行即可到达购物中心和地铁站，装修精致，配备全套高品质家电。', '上海市黄浦区南京东路', 5500.00, '月', 'https://images.unsplash.com/photo-1502672260266-1c1ef2d93688?auto=format&fit=crop&q=80', '市中心,交通便利,精致装修', 'apartments', 'monthly', 1, 4.8, 120),
    ('静谧林间北欧风民宿', '隐匿于莫干山林间，大落地窗设计，让您与大自然零距离接触，感受极致静谧。', '湖州市德清县莫干山', 1280.00, '晚', 'https://images.unsplash.com/photo-1587061949409-02df41d5e562?auto=format&fit=crop&q=80', '大自然,北欧风,网红打卡', 'homestays', 'featured', 1, 4.9, 85),
    ('海滨阳光景观大房', '推窗见海，下楼即是沙滩。清晨的第一缕阳光和咸咸的海风是这里最美的馈赠。', '三亚市亚龙湾旅游区', 880.00, '晚', 'https://images.unsplash.com/photo-1499793983690-e29da59ef1c2?auto=format&fit=crop&q=80', '一线海景,亲子度假,阳光充足', 'homestays', 'seaview', 1, 4.7, 210),
    ('工业风白领公寓', '专为时尚职场精英打造，Loft结构，极简设计，社区氛围浓厚。', '杭州市滨江区科技园', 4200.00, '月', 'https://images.unsplash.com/photo-1497366216548-37526070297c?auto=format&fit=crop&q=80', 'Loft,工业风,科技园旁', 'apartments', 'professional', 1, 4.6, 65),
    ('温馨邻舍整租公寓', '两室一厅，居家良选。周边配套设施完善，菜场、学校一应俱全，充满烟火气。', '成都市武侯区玉林路', 3500.00, '月', 'https://images.unsplash.com/photo-1484154218962-a1c002085d2f?auto=format&fit=crop&q=80', '整租,温馨社区,性价比高', 'apartments', 'entire', 1, 4.5, 45),
    ('京都风情传统住宅', '复刻日式庭院，榻榻米房，穿着浴衣在走廊边品茗，体验地道的京都慢生活。', '京都市东山区', 2200.00, '晚', 'https://images.unsplash.com/photo-1528360983277-13d901235fde?auto=format&fit=crop&q=80', '日式庭院,榻榻米,和风体验', 'overseas', 'japan', 1, 4.9, 150),
    ('伦敦泰晤士河畔公寓', '位于伦敦核心地带，可俯瞰泰晤士河美景，英伦复古与现代简约完美融合。', '伦敦市威斯敏斯特区', 150.00, '英镑/晚', 'https://images.unsplash.com/photo-1513635269975-59663e0ac1ad?auto=format&fit=crop&q=80', '河景房,古典英伦,位置优越', 'overseas', 'uk', 1, 4.8, 92),
    ('极简艺术设计公寓', '知名设计师倾情打造，每一处细节都彰显艺术品味，是寻找灵感的理想居所。', '上海市徐汇区安福路', 6500.00, '月', 'https://images.unsplash.com/photo-1618221195710-dd6b41faaea6?auto=format&fit=crop&q=80', '设计师款,艺术气息,高端社区', 'homestays', 'designer', 1, 4.9, 38),
    ('背包客温馨胶囊位', '虽是胶囊，但私密性极佳，公共区域很大，适合结交来自五湖四海的朋友。', '广州市越秀区', 120.00, '晚', 'https://images.unsplash.com/photo-1596409849204-a14db25e3678?auto=format&fit=crop&q=80', '极致性价比,胶囊仓,驴友聚集', 'hostels', 'capsule', 1, 4.4, 320),
    ('CBD核心商务套房', '顶级办公环境配顶级居住体验，管家式服务，助您在商海中游刃有余。', '北京市朝阳区国贸', 12000.00, '月', 'https://images.unsplash.com/photo-1486406146926-c627a92ad1ab?auto=format&fit=crop&q=80', 'CBD核心,高端商务,行政服务', 'business', 'cbd', 1, 4.7, 55),
    ('梦幻田园小筑', '四周环绕着金色的麦田，秋季可以收割，夏季可以数星星。', '大理市喜洲古镇', 450.00, '晚', 'https://images.unsplash.com/photo-1500076656116-558758c991c1?auto=format&fit=crop&q=80', '田园生活,网红麦田,浪漫', 'homestays', 'countryside', 1, 4.8, 115),
    ('大学城舒适合租房', '适合刚步入社会的学生或职场新人。独立房间，共享厨房，社交简单。', '南京市仙林大学城', 1800.00, '月', 'https://images.unsplash.com/photo-1555854877-bab0e564b8d5?auto=format&fit=crop&q=80', '学生党,极简生活,低租金', 'apartments', 'student', 1, 4.3, 78),
    ('首尔明洞时尚公寓', '下楼就是明洞步行街，购物达人的天堂，房间小而精悍。', '首尔市明洞区', 120000.00, '韩元/晚', 'https://images.unsplash.com/photo-1517154421773-052f83c4217c?auto=format&fit=crop&q=80', '购物中心,时尚首尔,交通枢纽', 'overseas', 'korea', 1, 4.6, 201),
    ('清迈小镇清新民宿', '充满热带风情的庭院，每天清晨在鸟鸣中醒来，咖啡馆星罗棋布。', '清迈市宁曼路', 300.00, '晚', 'https://images.unsplash.com/photo-1528181304800-259b08848526?auto=format&fit=crop&q=80', '清新文艺,泰国风情,慢节奏', 'overseas', 'thailand', 1, 4.9, 180),
    ('悉尼港风景工作室', '距离悉尼歌剧院步行仅10分钟，现代装修，配套一流。', '悉尼中心区域', 220.00, '澳元/晚', 'https://images.unsplash.com/photo-1523482580638-01c690b77091?auto=format&fit=crop&q=80', '歌剧院景观,现代简约,地标建筑', 'overseas', 'australia', 1, 4.8, 88),
    ('巴黎左岸古典民宿', '充满了塞纳河左岸的文艺气息，复古家具，带阳台。', '巴黎市第七区', 180.00, '欧元/晚', 'https://images.unsplash.com/photo-1471623432079-b009d30b6729?auto=format&fit=crop&q=80', '浪漫巴黎,文艺复古,塞纳河畔', 'overseas', 'europe', 1, 4.7, 66),
    ('背包探险者共居空间', '为志同道合的探险者准备，共享装备库，定期举办旅行讲座。', '昆明市盘龙区', 99.00, '晚', 'https://images.unsplash.com/photo-1529156069898-49953e39b3ac?auto=format&fit=crop&q=80', '旅行分享,低价格,社交活跃', 'hostels', 'social', 1, 4.5, 145),
    ('曼谷高空景观泳池房', '自带无边际泳池，夜晚可俯瞰整座曼谷城的繁华夜景。', '曼谷市沙吞区', 450.00, '晚', 'https://images.unsplash.com/photo-1506318137071-a8bcbf90d704?auto=format&fit=crop&w=800&q=80', '无边泳池,高空夜景,核心地标', 'overseas', 'singapore', 1, 4.8, 230),
    ('森林星空露营帐篷', '在森林中露营，帐篷顶是全透明的，躺着就能看繁星满天。', '浙江安吉灵峰景区', 580.00, '晚', 'https://images.unsplash.com/photo-1478131143081-80f7f84ca84d?auto=format&fit=crop&w=800&q=80', '星空睡眠,深度自然,独特体验', 'hostels', 'camping', 1, 4.6, 52),
    ('古北壹号尊贵寓所', '顶奢配置，24小时五星级贴心服务，为您的生活品质保驾护航。', '上海市闵行区古北', 45000.00, '月', 'https://images.unsplash.com/photo-1493809842364-78817add7ffb?auto=format&fit=crop&q=80', '顶奢公寓,管家服务,私密空间', '平价公寓', '长租公寓', 1, 5.0, 20),
    ('胡同里的旧时光民宿', '改造自传统四合院，门外是喧嚣的北京，门内是清净的民俗。', '北京市东城区南锣鼓巷', 1100.00, '晚', 'https://images.unsplash.com/photo-1599619351208-3e6c839d6828?auto=format&fit=crop&q=80', '老北京胡同,四合院,情怀', '精品民宿', '古村民宿', 1, 4.8, 160),
    ('阿尔卑斯山下小木屋', '木质结构，温暖的壁炉，是冬季滑雪的最佳休憩地。', '瑞士策马特小镇', 280.00, '瑞郎/晚', 'https://images.unsplash.com/photo-1449844908441-8829872d2607?auto=format&fit=crop&q=80', '雪山景观,温馨壁炉,滑雪胜地', '精品民宿', '山居民宿', 1, 4.9, 42),
    ('深圳湾人才公寓', '针对高层次人才专门打造，免押金，智能化管理。', '深圳市南山区深圳湾', 5800.00, '月', 'https://images.unsplash.com/photo-1497215728101-856f4ea42174?auto=format&fit=crop&q=80', '高新人才,智能家居,湾区风景', '商务出行', '商务中心', 1, 4.7, 105),
    ('三环内舒适两居', '位于三环内，多线地铁直达，生活功能分区明确。', '北京市西城区', 8500.00, '月', 'https://images.unsplash.com/photo-1484154218962-a1c002085d2f?auto=format&fit=crop&q=80', '三环内,稳定长租,高品质', '平价公寓', '长租公寓', 1, 4.6, 37),
    ('丽江古镇临水人家', '坐在窗边就能看到流水潺潺，是发呆和放空的好地方。', '丽江市大研古镇', 380.00, '晚', 'https://images.unsplash.com/photo-1502672260266-1c1ef2d93688?auto=format&fit=crop&q=80', '临水窗景,纳西风情,慢生活', 'homestays', 'featured', 1, 4.8, 195),
    ('纽约曼哈顿现代寓所', '位于曼哈顿心脏地带，步行前往时代广场，极富大都市快节奏感。', '纽约市曼哈顿区', 280.00, '美元/晚', 'https://images.unsplash.com/photo-1512453979798-5ea904ac66de?auto=format&fit=crop&q=80', '曼哈顿核心,现代摩登,高效率', '海外房源', '美国', 1, 4.7, 112),
    ('东京浅草寺邻近民宿', '出门即是历史悠久的浅草寺，周边布满了传统江户风格的小吃店。', '东京浅草区域', 18000.00, '日元/晚', 'https://images.unsplash.com/photo-1528360983277-13d901235fde?auto=format&fit=crop&q=80', '传统街区,寺庙旁,地道美食', 'overseas', 'japan', 1, 4.8, 255),
    ('西安城墙根下老宅', '推开窗就是厚重的古城墙，仿佛能穿越回那个辉盛的唐朝。', '西安市碑林区', 450.00, '晚', 'https://images.unsplash.com/photo-1599619351208-3e6c839d6828?auto=format&fit=crop&q=80', '古都风韵,历史遗迹,人文', '精品民宿', '古村民宿', 1, 4.7, 138),
    ('厦门环岛路海景房', '晨起看日出，暮时吹海风，与大海只有一条马路的距离。', '厦门市环岛南路', 680.00, '晚', 'https://images.unsplash.com/photo-1499793983690-e29da59ef1c2?auto=format&fit=crop&q=80', '一线海景,环岛路旁,清新浪漫', 'homestays', 'seaview', 1, 4.9, 310),
    ('青岛老洋房德式民宿', '红瓦绿树，碧海蓝天，居住在德式老别墅里，感受时光沉淀。', '青岛市市南区', 550.00, '晚', 'https://images.unsplash.com/photo-1587061949409-02df41d5e562?auto=format&fit=crop&w=800&q=80', '德式风情,老建筑,大海近在咫尺', 'homestays', 'featured', 1, 4.8, 150),
    ('广州塔下珠江美景房', '在房间里就能与“小蛮腰”合影，夜晚的珠江两岸灯火绚烂。', '广州市海珠区', 880.00, '晚', 'https://images.unsplash.com/photo-1486406146926-c627a92ad1ab?auto=format&fit=crop&q=80', '小蛮腰旁,绝美江景,高人气', '精品民宿', '热门民宿', 1, 4.8, 420),
    ('重庆洪崖洞江景客栈', '魔幻现实主义的视角，下楼即可穿梭在洪崖洞的灯影之中。', '重庆市渝中区', 350.00, '晚', 'https://images.unsplash.com/photo-1517154421773-052f83c4217c?auto=format&fit=crop&w=800&q=80', '穿楼体验,火锅之约,震撼夜景', '精品民宿', '热门民宿', 1, 4.6, 580),
    ('长沙五一广场中心寓所', '美食中心！楼下就是各种网红小吃店，满足你的味蕾。', '长沙市开福区', 400.00, '晚', 'https://images.unsplash.com/photo-1502672260266-1c1ef2d93688?auto=format&fit=crop&q=80', '吃货天堂,市中心,逛街极便', '精品民宿', '热门民宿', 1, 4.7, 390),
    ('阳朔遇龙河畔山水屋', '人在画中游。推窗即见秀美山水，可骑行可漂流。', '阳朔县遇龙河景区', 720.00, '晚', 'https://images.unsplash.com/photo-1449844908441-8829872d2607?auto=format&fit=crop&w=800&q=80', '世外桃源,桂林山水,户外运动', '精品民宿', '山居民宿', 1, 4.9, 215),
    ('武汉黄鹤楼旁复古公寓', '登高望远，历史名楼近在咫尺，体验地道汉派生活方式。', '武汉市武昌区', 420.00, '晚', 'https://images.unsplash.com/photo-1599619351208-3e6c839d6828?auto=format&fit=crop&w=800&q=80', '黄鹤楼旁,长江大桥近,江城文化', '精品民宿', '古村民宿', 1, 4.5, 120),
    ('杭州西湖隐世别院', '深藏在满觉陇，秋来桂花飘香，茶香伴着清幽，极尽江南韵律。', '杭州市西湖街道', 1580.00, '晚', 'https://images.unsplash.com/photo-1500076656116-558758c991c1?auto=format&fit=crop&w=800&q=80', '西湖秘境,桂香入室,江南美学', 'homestays', 'featured', 1, 4.9, 75),
    ('苏州平江路枕河人家', '小桥流水人家。白墙黛瓦，吴侬软语，感受苏州城的细腻与温柔。', '苏州市姑苏区', 680.00, '晚', 'https://images.unsplash.com/photo-1587061949409-02df41d5e562?auto=format&fit=crop&w=800&q=80', '平江路上,听昆曲,老派苏州', 'homestays', 'featured', 1, 4.8, 185),
    ('大连俄罗斯风情街套房', '充满异域色彩的街道，欧式老房设计，非常适合拍照出片。', '大连市西岗区', 450.00, '晚', 'https://images.unsplash.com/photo-1513635269975-59663e0ac1ad?auto=format&fit=crop&w=800&q=80', '异国风情,复古外墙,拍照网红', 'homestays', 'featured', 1, 4.6, 95),
    ('南京新街口高空景观房', '位于中华第一座商圈，在高处俯瞰南京城的灯火阑珊，尽显繁华。', '南京市秦淮区', 600.00, '晚', 'https://images.unsplash.com/photo-1486406146926-c627a92ad1ab?auto=format&fit=crop&w=800&q=80', '俯瞰市中心,交通无压力,高端品味', '精品民宿', '热门民宿', 1, 4.7, 260),
    ('昆明翠湖边阳光大床', '冬日里可以在湖边喂红嘴鸥，四季如春，适合避霾和养老。', '昆明市五华区', 280.00, '晚', 'https://images.unsplash.com/photo-1502672260266-1c1ef2d93688?auto=format&fit=crop&w=800&q=80', '春城日光,喂红嘴鸥,慢生活节奏', '精品民宿', '热门民宿', 1, 4.8, 140),
    ('成都宽窄巷子清幽院落', '大隐隐于市。在繁华的宽窄巷子里拥有一方宁静的小院，喝茶打盹。', '成都市青羊区', 1200.00, '晚', 'https://images.unsplash.com/photo-1599619351208-3e6c839d6828?auto=format&fit=crop&w=800&q=80', '宽窄巷内,川西民居,私密宁静', 'homestays', 'featured', 1, 4.9, 110),
    ('哈尔滨中央大街欧陆房', '索菲亚教堂就在不远处，冬日看雪，享受浓厚的异国风味。', '哈尔滨市道里区', 480.00, '晚', 'https://images.unsplash.com/photo-1513635269975-59663e0ac1ad?auto=format&fit=crop&w=800&q=80', '冰城冬韵,欧式长街,美食之旅', 'homestays', 'featured', 1, 4.7, 220),
    ('哈尔滨雪乡温馨土炕', '外面是零下三十度，里面是热乎乎的大炕，体验极致的东北风情。', '海林市雪乡景区', 350.00, '晚', 'https://images.unsplash.com/photo-1500076656116-558758c991c1?auto=format&fit=crop&w=800&q=80', '极致体验,东北年味,林海雪原', 'homestays', 'countryside', 1, 4.5, 330),
    ('西双版纳热带雨林房', '仿佛居住在森林里，周边是大象和孔雀，体验傣族的神奇文化。', '景洪市告庄西双景', 650.00, '晚', 'https://images.unsplash.com/photo-1449844908441-8829872d2607?auto=format&fit=crop&w=800&q=80', '热带雨林,傣族风情,避寒胜地', 'homestays', 'featured', 1, 4.8, 205),
    ('张家界神仙居山景房', '推窗即是石笋森林，早起看云海起伏，仿佛遗落的人间仙境。', '张家界武陵源区', 980.00, '晚', 'https://images.unsplash.com/photo-1449844908441-8829872d2607?auto=format&fit=crop&w=800&q=80', '云海仙境,奇峰异石,世外秘境', '精品民宿', '山居民宿', 1, 4.9, 125),
    ('敦煌鸣沙山月牙泉景房', '看大漠孤烟直，听驼铃声声远，在沙漠边缘感受历史的厚重。', '敦煌市鸣沙山景区', 850.00, '晚', 'https://images.unsplash.com/photo-1599619351208-3e6c839d6828?auto=format&fit=crop&w=800&q=80', '沙漠风光,丝路情怀,绝美日落', '精品民宿', '古村民宿', 1, 4.7, 98),
    ('拉萨布达拉宫景观房', '抬头就能望见庄严的布达拉宫，在日光之城寻找心灵的纯净。', '拉萨市城关区', 1100.00, '晚', 'https://images.unsplash.com/photo-1599619351208-3e6c839d6828?auto=format&fit=crop&w=800&q=80', '朝圣之旅,日光之城,壮丽景观', 'homestays', 'featured', 1, 4.8, 85),
    ('乌镇西栅枕河人家', '梦里的水乡。入住在西栅景区内，清晨在水流声中慢慢苏醒。', '嘉兴市桐乡乌镇', 950.00, '晚', 'https://images.unsplash.com/photo-1587061949409-02df41d5e562?auto=format&fit=crop&w=800&q=80', '由于水乡,桨声灯影,江南旧梦', 'homestays', 'featured', 1, 4.9, 240),
    ('平遥古城老商号客栈', '住在晋商的老宅里，穿着古装在深宅大院里穿行，体验晋商文化。', '平遥古城景区内', 420.00, '晚', 'https://images.unsplash.com/photo-1599619351208-3e6c839d6828?auto=format&fit=crop&w=800&q=80', '晋商文化,古城核心,历史名城', '精品民宿', '古村民宿', 1, 4.7, 165),
    ('贵州西江千户苗寨观景', '夜晚看万家灯火亮起，如繁星跌落凡尘，感受苗族文化的独特魅力。', '雷山县西江苗寨', 550.00, '晚', 'https://images.unsplash.com/photo-1449844908441-8829872d2607?auto=format&fit=crop&w=800&q=80', '万家灯火,民族风情,摄影圣地', 'homestays', 'featured', 1, 4.8, 290);
